#include <iostream>
class timer {
    public:
               timer(const char *name = 0);
               timer(const char *name, std::ostream &write_on_exit);
               ~timer();
    void       start(), stop();
    void       reset();
    std::ostream &print(std::ostream &);
    double     getTimeInSeconds();
    private:
    void       print_time(std::ostream &, const char *which, double time) const;
    union {
        long long   total_time;
        struct {
#if defined __PPC__
            int   high, low;
#else
            int   low, high;
#endif
        };
    };
    unsigned long long count;
    const char   *const name;
    std::ostream   *const write_on_exit;
    static double   CPU_speed_in_MHz, get_CPU_speed_in_MHz();
};
std::ostream &operator << (std::ostream &, class timer &);
inline void timer::reset() { total_time = 0; count = 0; }
inline timer::timer(const char *name) : name(name), write_on_exit(0) { reset(); }
inline timer::timer(const char *name, std::ostream &write_on_exit) : name(name), write_on_exit(&write_on_exit) { reset(); }
inline timer::~timer() { if (write_on_exit != 0) print(*write_on_exit); }
inline void timer::start() {
#if (defined __GNUC__ || defined __INTEL_COMPILER) && (defined __i386 || defined __x86_64)
    asm volatile ("rdtsc\n\t" "subl %%eax, %0\n\t" "sbbl %%edx, %1" : "+m" (low), "+m" (high) : : "eax", "edx");
#else
    total_time = 0;
#endif
}
inline void timer::stop() {
#if (defined __GNUC__ || defined __INTEL_COMPILER) && (defined __i386 || defined __x86_64)
    asm volatile ("rdtsc\n\t" "addl %%eax, %0\n\t" "adcl %%edx, %1" : "+m" (low), "+m" (high) : : "eax", "edx");
#endif
    ++ count;
}
double timer::CPU_speed_in_MHz = timer::get_CPU_speed_in_MHz();
double timer::get_CPU_speed_in_MHz() {
#if defined __linux__
    std::ifstream infile("/proc/cpuinfo");
    char     buffer[256], *colon;
    while (infile.good()) {
        infile.getline(buffer, 256);
        if (strncmp("cpu MHz", buffer, 7) == 0 && (colon = strchr(buffer, ':')) != 0)
            return atof(colon + 2);
    }
#endif
    return 0.0;
}
void timer::print_time(std::ostream &str, const char *which, double time) const {
    static const char *units[] = { " ns", " us", " ms", "  s", " ks", 0 };
    const char      **unit   = units;
    time = 1000.0 * time / CPU_speed_in_MHz;
    while (time >= 999.5 && unit[1] != 0) { time /= 1000.0; ++ unit; }
    str << which << " = " << std::setprecision(3) << std::setw(4) << time << *unit;
}
std::ostream &timer::print(std::ostream &str) {
    str << std::left << std::setw(25) << (name != 0 ? name : "timer") << ": " << std::right;
    if (CPU_speed_in_MHz == 0) str << "could not determine CPU speed\n";
    else if (count > 0) {
        double total = static_cast<double>(total_time);
        print_time(str, "avg", total / static_cast<double>(count));
        print_time(str, ", total", total);
        str << ", count = " << std::setw(9) << count << '\n';
    }
    else str << "not used\n";
    return str;
}
std::ostream &operator << (std::ostream &str, class timer &t) { return t.print(str); }
double timer::getTimeInSeconds() {
    double total = static_cast<double>(total_time);
    double res = (total / 1000000.0) / CPU_speed_in_MHz;
    return res;
}
